function BmiTool() {
  const settings = useSettings();
  const dietProfile = useDietProfile();
  const [sex, setSex] = useState<Sex>(dietProfile?.sex ?? settings?.gender ?? "male");
  const [age, setAge] = useState(dietProfile?.age ?? 28);
  const [height, setHeight] = useState(dietProfile?.heightCm ?? 175);
  const [weight, setWeight] = useState(dietProfile?.weightKg ?? 75);
  const bmi = weight / (height / 100) ** 2;
  const category = bmi < 18.5 ? BMI_BANDS[0] : bmi < 25 ? BMI_BANDS[1] : bmi < 30 ? BMI_BANDS[2] : BMI_BANDS[3];
  const marker = Math.min(100, Math.max(0, ((bmi - 15) / 25) * 100));
  const percentile = bmi < 18.5 ? 9 : bmi < 25 ? 42 : bmi < 30 ? 72 : bmi < 35 ? 88 : 96;
  const planHint = planByAgeGoal(age, sex, bmi);

  return (
    <ToolCard title="محاسبه‌گر حرفه‌ای BMI" subtitle="تحلیل سریع وزن نسبت به قد، با محدودیت‌های علمی BMI.">
      <div className="grid grid-cols-2 gap-3">
        <SelectField label="جنسیت" value={sex} onChange={(v) => setSex(v as Sex)} options={[["male", "آقا"], ["female", "خانم"]]} />
        <NumberField label="سن" value={age} onChange={setAge} suffix="سال" min={12} max={100} />
        <NumberField label="قد" value={height} onChange={setHeight} suffix="cm" min={120} max={230} />
        <NumberField label="وزن" value={weight} onChange={setWeight} suffix="kg" min={30} max={250} />
      </div>

      <div className="mt-4 rounded-2xl bg-card2 p-4 ring-1 ring-line">
        <div className="flex items-end justify-between">
          <div>
            <p className="text-xs font-bold text-faint">BMI شما</p>
            <p className="mt-1 text-4xl font-black text-ink" dir="ltr">{bmi.toFixed(1)}</p>
          </div>
          <span className={cn("rounded-full px-3 py-1 text-xs font-black text-black", category.color)}>{category.label}</span>
        </div>
        <div className="relative mt-4 h-4 overflow-hidden rounded-full bg-card ring-1 ring-line">
          <div className="absolute inset-y-0 right-0 w-[14%] bg-sky-400" />
          <div className="absolute inset-y-0 right-[14%] w-[26%] bg-brand" />
          <div className="absolute inset-y-0 right-[40%] w-[20%] bg-amber-400" />
          <div className="absolute inset-y-0 right-[60%] w-[40%] bg-rose-400" />
          <span className="absolute top-1/2 size-5 -translate-y-1/2 rounded-full border-2 border-white bg-black shadow-lg" style={{ right: `${marker}%` }} />
        </div>
        <div className="mt-3 grid grid-cols-3 gap-2 text-center">
          <MiniStat label="گروه مشابه" value={`${percentile}%`} />
          <MiniStat label="وزن سالم حدودی" value={`${healthyWeight(height)[0]}-${healthyWeight(height)[1]} kg`} />
          <MiniStat label="سن/جنس" value={sex === "male" ? `مرد ${age}` : `زن ${age}`} />
        </div>
        <p className="mt-3 text-xs leading-6 text-muted">
          این درصد یک تخمین آموزشی برای جایگاه شما در گروه BMI است، نه آمار قطعی ایران. BMI عضله، دور کمر و چربی بدن را مستقیم نمی‌سنجد.
        </p>
      </div>

      <Guidance title="تحلیل و پیشنهاد رمق" items={[category.advice, planHint.exercise, planHint.nutrition]} />
    </ToolCard>
  );
}

