function KnowledgeTool() {
  const settings = useSettings();
  const { index } = useExercises();
  const [group, setGroup] = useState<KnowledgeGroup>("movements");
  const [query, setQuery] = useState("");
  const gender: Gender = settings?.gender ?? "male";
  const exerciseItems = useMemo(
    () => (index?.all ?? []).map((exercise) => exerciseToKnowledgeItem(exercise, gender)),
    [gender, index],
  );
  const data = useMemo(() => {
    const base = EXPANDED_KNOWLEDGE[group];
    if (group === "training") {
      return {
        ...base,
        items: dedupeKnowledgeItems([...buildAgeSexTrainingItems(exerciseItems), ...base.items]),
      };
    }
    if (group !== "movements") return base;
    return {
      ...base,
      items: [...MOVEMENT_GLOSSARY, ...exerciseItems],
    };
  }, [exerciseItems, group]);
  const items = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return data.items;
    return data.items.filter((item) =>
      `${item.name} ${item.aliases?.join(" ") ?? ""} ${item.use} ${item.how} ${item.caution} ${item.dose ?? ""} ${item.timing ?? ""} ${item.evidence ?? ""} ${item.tags.join(" ")} ${item.muscles?.join(" ") ?? ""} ${item.equipment ?? ""} ${item.level ?? ""} ${item.related?.map((move) => `${move.name} ${move.tags.join(" ")} ${move.muscles?.join(" ") ?? ""}`).join(" ") ?? ""}`
        .toLowerCase()
        .includes(q),
    );
  }, [data.items, query]);
  const visibleItems = group === "movements" && !query.trim() ? items.slice(0, 90) : items.slice(0, 180);
  const hiddenCount = Math.max(0, items.length - visibleItems.length);

  return (
    <ToolCard title="دانشنامه AI Fitness ایران" subtitle="حرکات بدنسازی با عکس/ویدیو، فازهای تمرین، اصطلاحات باشگاهی، مکمل، تغذیه، دستگاه‌های آنالیز و نکات ایمنی.">
      <div className="rounded-2xl bg-brand/10 p-4 ring-1 ring-brand/20">
        <p className="text-sm font-black text-ink">هدف رمق</p>
        <p className="mt-2 text-xs leading-6 text-muted">
          ساختن اولین مرجع AI Fitness فارسی برای کاربر ایرانی: داده، تعریف، کاربرد، خطر، تمرین، تغذیه، تجهیزات و مسیر سؤال از مربی/پزشک.
        </p>
      </div>
      <div className="mt-3 flex items-center gap-2 rounded-2xl bg-card2 px-3 py-2 ring-1 ring-line">
        <Icon name="search" className="size-4 text-faint" />
        <input
          value={query}
          onChange={(event) => setQuery(event.target.value)}
          placeholder="جستجو: اسکات با دمبل، لاری با دستگاه، کات، RIR، کراتین..."
          className="min-w-0 flex-1 bg-transparent text-sm font-bold text-ink outline-none placeholder:text-faint"
        />
      </div>
      <div className="no-scrollbar -mx-1 mt-3 flex gap-2 overflow-x-auto px-1">
        {GROUPS.map((item) => (
          <button
            key={item.id}
            type="button"
            onClick={() => setGroup(item.id)}
            className={cn("h-8 flex-shrink-0 rounded-full px-3 text-xs font-black", group === item.id ? "bg-brand text-brandink" : "bg-card2 text-muted ring-1 ring-line")}
          >
            {item.label}
          </button>
        ))}
      </div>
      <div className="mt-4 flex items-center justify-between gap-3">
        <h3 className="text-sm font-black text-ink">{data.title}</h3>
        <span className="rounded-full bg-card2 px-2.5 py-1 text-[10px] font-black text-brand ring-1 ring-line">
          {items.length.toLocaleString("fa-IR")} مورد
        </span>
      </div>
      {hiddenCount > 0 && (
        <p className="mt-2 rounded-2xl bg-card2 p-3 text-[11px] leading-6 text-muted ring-1 ring-line">
          برای سرعت بهتر، فقط {visibleItems.length.toLocaleString("fa-IR")} مورد اول نمایش داده شده؛ با جستجو عباراتی مثل «اسکات»، «لاری»، «کابل»، «سرشانه» یا «دمبل» همه نتایج مرتبط را ببین.
        </p>
      )}
      <div className="mt-3 space-y-3">
        {visibleItems.map((item) => (
          <KnowledgeDetails key={`${item.name}-${item.href ?? ""}`} item={item} />
        ))}
      </div>
      <div className="mt-4 rounded-2xl bg-card2 p-4 text-xs leading-6 text-muted ring-1 ring-line">
        منابع پایه: CDC/NHLBI برای BMI، ACSM/CDC برای فعالیت و تمرین مقاومتی، NIH Office of Dietary Supplements برای مکمل‌ها. این دانشنامه باید به‌مرور با پزشک، فیزیوتراپیست و مربی ایرانی کامل‌تر شود.
      </div>
    </ToolCard>
  );
}

