function TabButton({ active, label, icon, onClick }: { active: boolean; label: string; icon: "scale" | "utensils" | "library"; onClick: () => void }) {
  return (
    <button type="button" onClick={onClick} className={cn("rounded-2xl px-2 py-3 text-xs font-black ring-1", active ? "bg-brand text-brandink ring-brand" : "bg-card2 text-muted ring-line")}>
      <Icon name={icon} className="mx-auto mb-1 size-5" />
      {label}
    </button>
  );
}

function ToolCard({ title, subtitle, children }: { title: string; subtitle: string; children: React.ReactNode }) {
  return (
    <div className="mt-3 rounded-3xl bg-card p-4 ring-1 ring-line">
      <h2 className="text-lg font-black text-ink">{title}</h2>
      <p className="mt-1 text-xs leading-6 text-muted">{subtitle}</p>
      <div className="mt-4">{children}</div>
    </div>
  );
}

function NumberField({ label, value, onChange, suffix, min, max }: { label: string; value: number; onChange: (value: number) => void; suffix: string; min: number; max: number }) {
  return (
    <label className="block">
      <span className="mb-1.5 block text-xs font-bold text-faint">{label}</span>
      <span className="flex items-center rounded-2xl bg-card2 px-3 ring-1 ring-line">
        <input type="number" value={value} min={min} max={max} onChange={(event) => onChange(Number(event.target.value))} className="w-full bg-transparent py-2.5 text-sm font-black text-ink outline-none" />
        <span className="text-[11px] font-bold text-faint">{suffix}</span>
      </span>
    </label>
  );
}

function SelectField({ label, value, onChange, options }: { label: string; value: string; onChange: (value: string) => void; options: [string, string][] }) {
  return (
    <label className="block">
      <span className="mb-1.5 block text-xs font-bold text-faint">{label}</span>
      <select value={value} onChange={(event) => onChange(event.target.value)} className="h-11 w-full rounded-2xl bg-card2 px-3 text-sm font-black text-ink outline-none ring-1 ring-line">
        {options.map(([id, labelText]) => <option key={id} value={id}>{labelText}</option>)}
      </select>
    </label>
  );
}

function MiniStat({ label, value }: { label: string; value: string }) {
  return (
    <div className="rounded-xl bg-card px-2 py-2 ring-1 ring-line">
      <p className="text-[10px] font-bold text-faint">{label}</p>
      <p className="mt-1 text-xs font-black text-ink" dir="ltr">{value}</p>
    </div>
  );
}

function BigStat({ label, value, unit }: { label: string; value: string; unit: string }) {
  return (
    <div className="rounded-2xl bg-card2 p-4 ring-1 ring-line">
      <p className="text-[11px] font-bold text-faint">{label}</p>
      <p className="mt-1 text-2xl font-black text-ink" dir="ltr">{value}</p>
      <p className="text-[10px] font-bold text-brand">{unit}</p>
    </div>
  );
}

function Guidance({ title, items }: { title: string; items: string[] }) {
  return (
    <div className="mt-4 rounded-2xl bg-card2 p-4 ring-1 ring-line">
      <h3 className="text-sm font-black text-ink">{title}</h3>
      <ul className="mt-3 space-y-2">
        {items.map((item) => (
          <li key={item} className="flex gap-2 text-xs leading-6 text-muted">
            <span className="mt-2 size-1.5 flex-shrink-0 rounded-full bg-brand" />
            <span>{item}</span>
          </li>
        ))}
      </ul>
    </div>
  );
}

interface KnowledgeItem {
  name: string;
  use: string;
  how: string;
  caution: string;
  tags: string[];
  dose?: string;
  timing?: string;
  evidence?: string;
  aliases?: string[];
  muscles?: string[];
  equipment?: string;
  level?: string;
  kind?: string;
  href?: string;
  related?: KnowledgeItem[];
  media?: {
    type: "image" | "video";
    src: string;
    poster?: string;
  };
}

function entry(name: string, use: string, how: string, caution: string, tags: string[], meta: Pick<KnowledgeItem, "dose" | "timing" | "evidence"> = {}): KnowledgeItem {
  return { name, use, how, caution, tags, ...meta };
}

