function pickRelatedMoves(exercises: KnowledgeItem[], termGroups: string[][], limit: number) {
  const picked: KnowledgeItem[] = [];
  for (const terms of termGroups) {
    const found = exercises
      .filter((exercise) => knowledgeItemMatchesTerms(exercise, terms))
      .sort((a, b) => Number(b.media?.type === "video") - Number(a.media?.type === "video"))[0];
    if (found && !picked.some((item) => item.href === found.href || item.name === found.name)) picked.push(found);
    if (picked.length >= limit) break;
  }
  return picked;
}

function knowledgeItemMatchesTerms(item: KnowledgeItem, terms: string[]) {
  const haystack = normalizeKnowledgeText(
    `${item.name} ${item.aliases?.join(" ") ?? ""} ${item.tags.join(" ")} ${item.muscles?.join(" ") ?? ""} ${item.equipment ?? ""}`,
  );
  return terms.some((term) => haystack.includes(normalizeKnowledgeText(term)));
}

function exerciseToKnowledgeItem(exercise: Exercise, gender: Gender): KnowledgeItem {
  const clip = firstExerciseClip(exercise, gender);
  const faName = exercise.name_fa || translateExerciseName(exercise.name);
  const muscles = [...exercise.primaryMuscles, ...exercise.secondaryMuscles].map(tMuscle);
  const equipment = tEquipment(exercise.category);
  const kind = exercise.mechanic === "Compound" ? "چندمفصلی" : exercise.mechanic === "Isolation" ? "تک‌مفصلی" : "حرکت";
  const force = exercise.force === "Push" ? "فشاری" : exercise.force === "Pull" ? "کششی" : exercise.force === "Hold" ? "ایزومتریک" : "تمرینی";
  const firstStep = exercise.steps_fa?.[0] || exercise.steps[0] || "حرکت را با کنترل، دامنه مناسب و فرم پایدار اجرا کنید.";
  const secondStep = exercise.steps_fa?.[1] || exercise.steps[1] || "وزنه و دامنه را بر اساس سطح و مفصل خود تنظیم کنید.";

  return {
    name: `${faName} / ${exercise.name}`,
    use: `${faName} یک حرکت ${kind} و ${force} با ابزار ${equipment} است که بیشتر روی ${muscles.slice(0, 3).join("، ") || "عضلات هدف"} کار می‌کند.`,
    how: `${firstStep} ${secondStep}`,
    caution: exercise.difficulty === "Advanced"
      ? "این حرکت پیشرفته است؛ قبل از افزایش وزنه، دامنه، تنفس و کنترل مرکز بدن را با مربی یا فیلم فرم بررسی کنید."
      : "حرکت را بدون درد تیز اجرا کنید؛ اگر فرم به‌هم می‌ریزد، وزنه یا دامنه را کم کنید.",
    tags: [
      faName,
      exercise.name,
      exercise.category,
      equipment,
      exercise.difficulty,
      ...muscles.slice(0, 4),
      ...autoAliasesForExercise(exercise),
    ],
    aliases: autoAliasesForExercise(exercise),
    muscles,
    equipment,
    level: tDifficulty(exercise.difficulty),
    kind,
    href: `/library/${exercise.slug}`,
    media: clip
      ? { type: "video", src: videoSrc(clip), poster: clip.poster ?? exercise.thumbnail ?? undefined }
      : exercise.thumbnail
        ? { type: "image", src: exercise.thumbnail, poster: exercise.thumbnail }
        : undefined,
    dose: exercise.mechanic === "Compound" ? "برای بیشتر برنامه‌ها ۳ تا ۵ ست؛ قدرت ۳ تا ۶ تکرار، حجم ۶ تا ۱۲ تکرار." : "برای بیشتر برنامه‌ها ۲ تا ۴ ست؛ معمولا ۱۰ تا ۲۰ تکرار با کنترل خوب.",
    timing: "در روز عضله هدف یا فول‌بادی؛ قبل از حرکات ایزوله، حرکات تکنیکی و سنگین‌تر را زودتر بگذارید.",
    evidence: "بر پایه دیتاست تمرینی MuscleWiki داخل اپ، همراه با ویدیو/تصویر و مراحل اجرا.",
  };
}

function firstExerciseClip(exercise: Exercise, gender: Gender): VideoClip | undefined {
  const preferred = exercise.videos[gender];
  const fallback = exercise.videos[gender === "male" ? "female" : "male"];
  return preferred.find((clip) => clip.angle.toLowerCase().includes("front")) || preferred[0] || fallback[0];
}

function autoAliasesForExercise(exercise: Exercise): string[] {
  const name = exercise.name.toLowerCase();
  const aliases: string[] = [];
  if (name.includes("dumbbell") && name.includes("squat")) aliases.push("اسکات با دمبل", "دمبل اسکات", "Dumbbell Squat");
  if (name.includes("barbell") && name.includes("squat")) aliases.push("اسکات با هالتر", "اسکات هالتر", "Barbell Squat");
  if (name.includes("machine") && name.includes("preacher")) aliases.push("لاری با دستگاه", "جلو بازو لاری دستگاه", "Machine Preacher Curl");
  if (name.includes("preacher")) aliases.push("جلو بازو لاری", "لاری", "Preacher Curl");
  if (name.includes("curl")) aliases.push("جلو بازو", "curl");
  if (name.includes("bench press")) aliases.push("پرس سینه", "پرس خوابیده");
  if (name.includes("lat pulldown")) aliases.push("لت پول دان", "لت سیم کش", "زیر بغل سیم کش");
  if (name.includes("row")) aliases.push("روئینگ", "قایقی", "زیر بغل");
  if (name.includes("deadlift")) aliases.push("ددلیفت", "هیپ هینج");
  if (name.includes("romanian") || name.includes("stiff")) aliases.push("ددلیفت رومانیایی", "RDL", "پشت ران");
  if (name.includes("lateral raise")) aliases.push("نشر جانب", "سرشانه میانی");
  if (name.includes("tricep") || name.includes("triceps")) aliases.push("پشت بازو", "سه سر");
  if (name.includes("leg press")) aliases.push("پرس پا", "دستگاه پرس پا");
  if (name.includes("hip thrust")) aliases.push("هیپ تراست", "باسن");
  if (name.includes("lunge")) aliases.push("لانج", "لانگز");
  if (name.includes("fly")) aliases.push("فلای", "قفسه");
  return aliases;
}

function translateExerciseName(name: string) {
  return name
    .replaceAll("Dumbbell", "دمبل")
    .replaceAll("Barbell", "هالتر")
    .replaceAll("Machine", "دستگاه")
    .replaceAll("Cable", "کابل")
    .replaceAll("Bodyweight", "وزن بدن")
    .replaceAll("Squat", "اسکات")
    .replaceAll("Curl", "جلو بازو")
    .replaceAll("Preacher", "لاری")
    .replaceAll("Bench Press", "پرس سینه")
    .replaceAll("Deadlift", "ددلیفت")
    .replaceAll("Row", "روئینگ")
    .replaceAll("Press", "پرس")
    .replaceAll("Raise", "نشر")
    .replaceAll("Lunge", "لانج");
}

function tEquipment(value: string) {
  return ({
    Barbell: "هالتر",
    Dumbbells: "دمبل",
    Dumbbell: "دمبل",
    Machine: "دستگاه",
    Cable: "کابل",
    Bodyweight: "وزن بدن",
    Kettlebells: "کتل‌بل",
    Band: "کش",
    Smith: "اسمیت",
  } as Record<string, string>)[value] ?? value;
}

function tDifficulty(value: string) {
  return ({
    Novice: "مبتدی",
    Beginner: "شروعی",
    Intermediate: "متوسط",
    Advanced: "پیشرفته",
  } as Record<string, string>)[value] ?? value;
}

function tMuscle(value: string) {
  return ({
    Chest: "سینه",
    Biceps: "جلو بازو",
    Triceps: "پشت بازو",
    Shoulders: "سرشانه",
    Quads: "چهارسر ران",
    Hamstrings: "پشت ران",
    Glutes: "باسن",
    "Lower back": "پایین کمر",
    Lats: "لت",
    Traps: "کول",
    Calves: "ساق",
    Abdominals: "شکم",
    Forearms: "ساعد",
  } as Record<string, string>)[value] ?? value;
}

function healthyWeight(heightCm: number) {
  const m2 = (heightCm / 100) ** 2;
  return [Math.round(18.5 * m2), Math.round(24.9 * m2)];
}

function planByAgeGoal(age: number, sex: Sex, bmi: number) {
  const older = age >= 50;
  const young = age < 18;
  const female = sex === "female";
  return {
    exercise: young
      ? "تمرین پیشنهادی: وزن بدن، تکنیک، بازی، کش و یادگیری فرم؛ رکوردگیری سنگین نه."
      : older
        ? "تمرین پیشنهادی: دو تا سه جلسه قدرتی، تعادل، راه‌رفتن و موبیلیتی مفصل‌ها."
        : bmi >= 30
          ? "تمرین پیشنهادی: شروع با فول‌بادی کم‌فشار، قدم روزانه و افزایش آرام حجم تمرین."
          : "تمرین پیشنهادی: ۳ تا ۵ جلسه قدرتی با الگوهای اسکوات، پرس، کشش، هیپ‌هینج و مرکز بدن.",
    nutrition: female
      ? "تغذیه پیشنهادی: پروتئین کافی، آهن/ویتامین D با آزمایش، و پرهیز از رژیم خیلی کم‌کالری."
      : "تغذیه پیشنهادی: پروتئین روزانه، سبزی/فیبر، کنترل کالری و خواب کافی برای هورمون و ریکاوری.",
  };
}

function activityLabel(value: ActivityLevel) {
  return {
    sedentary: "کم‌تحرک",
    light: "سبک ۱-۳ روز",
    moderate: "متوسط ۳-۵ روز",
    active: "فعال ۶-۷ روز",
    athlete: "ورزشکار/کار سخت",
  }[value];
}

function mealSuggestions(profile: DietProfile, targets: ReturnType<typeof macroTargets>) {
  const meals = profile.mealsPerDay;
  return [
    { title: "صبحانه", text: `${Math.round(targets.kcal * 0.25)} کالری؛ پروتئین + نان/جو + میوه` },
    { title: "ناهار", text: `${Math.round(targets.kcal * 0.35)} کالری؛ برنج/نان + مرغ/حبوبات + سبزی` },
    { title: "شام", text: `${Math.round(targets.kcal * 0.25)} کالری؛ پروتئین سبک + سبزی + کربوهیدرات کنترل‌شده` },
    { title: "میان‌وعده", text: meals > 3 ? `${Math.round(targets.kcal * 0.15)} کالری؛ ماست/میوه/مغزها/وی` : "اگر گرسنه شدی: میوه یا ماست پروتئینی" },
  ];
}
